import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import { getAllProjects } from "../../api/api";

const ManageProjects = () => {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const res = await getAllProjects();
      setProjects(res.data);
      setLoading(false);
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">

      {/* SIDEBAR */}
      <Sidebar />

      {/* MAIN CONTENT */}
      <div className="flex-1 ml-64 p-8">

        <h1 className="text-3xl font-bold mb-8">
          All Projects
        </h1>

        {loading ? (
          <p>Loading...</p>
        ) : (
          <div className="space-y-6">

            {projects.length > 0 ? (
              projects.map((project) => (
                <div
                  key={project.id}
                  className="bg-white p-6 rounded-2xl shadow hover:shadow-md transition"
                >

                  {/* HEADER */}
                  <div className="flex justify-between items-center">
                    <h2 className="text-xl font-semibold">
                      {project.title}
                    </h2>

                    <span
                      className={`px-3 py-1 rounded-full text-sm font-medium ${
                        project.status === "completed"
                          ? "bg-gray-200 text-gray-700"
                          : project.status === "in-progress"
                          ? "bg-blue-100 text-blue-600"
                          : "bg-green-100 text-green-600"
                      }`}
                    >
                      {project.status || "open"}
                    </span>
                  </div>

                  {/* DESCRIPTION */}
                  <p className="text-gray-600 mt-2">
                    {project.description}
                  </p>

                  {/* TAGS (Optional if exists) */}
                  {project.skills && (
                    <div className="flex flex-wrap gap-2 mt-3">
                      {project.skills.map((skill, index) => (
                        <span
                          key={index}
                          className="bg-gray-100 px-3 py-1 rounded-full text-sm"
                        >
                          {skill}
                        </span>
                      ))}
                    </div>
                  )}

                  {/* FOOTER INFO */}
                  <div className="flex justify-between items-center mt-5 text-sm text-gray-500 border-t pt-4">

                    <div className="flex gap-6">
                      <span>💰 ₹{project.budget}</span>
                      <span>📅 {project.deadline || "Apr 20, 2026"}</span>
                      <span>🏢 {project.company || "Company Name"}</span>
                    </div>

                    <span className="text-teal-600 font-medium">
                      {project.proposals || 0} proposals
                    </span>

                  </div>

                </div>
              ))
            ) : (
              <p>No Projects Found</p>
            )}

          </div>
        )}

      </div>
    </div>
  );
};

export default ManageProjects;
